async function drawPieChart(arg_cnv,arg_dat,arg_colors){
try{
   var ws_cnv = document.getElementById(arg_cnv);
   var ws_context = ws_cnv.getContext("2d" );
   var ws_len = arg_dat.length;
   var ws_total = 0;
   for(var i = 0; i < ws_len; i++){
      ws_total += arg_dat[i];
   }
   var x = 100;
   var y = 100;
   var radius = 92;
   var startingPoint = 1.50;
   for(var i = 0; i < ws_len; i++){
      var percent = arg_dat[i] * 100 / ws_total;
      var endPoint = startingPoint + ( 2 / 100 * percent );
      ws_context.beginPath();
      ws_context.fillStyle = arg_colors[i];
      ws_context.moveTo( x, y );
      ws_context.arc( x, y, radius, startingPoint * Math.PI, endPoint * Math.PI );
      ws_context.fill();
      startingPoint = endPoint;
   }
}catch(err){alert(err);}
